solutions.python:
class Solution:
	def is_even(self, n: int) -> bool:
        if n < 0:
            n = abs(n)
        return n % 2 == 0

def main():
    n = int(input())
    solution = Solution()
    result = solution.is_even(n)
    print(result)
if __name__ == '__main__':
    main()

